#!/bin/bash
set -e
echo "Creating TaskFlow file structure..."

mkdir -p app/api/tasks/\[id\] app/api/people app/api/ai-query lib

# ── app/layout.tsx ──────────────────────────────────────────────────────────
cat > app/layout.tsx << 'EOF'
// app/layout.tsx
import type { Metadata } from "next";
import "./globals.css";

export const metadata: Metadata = {
  title: "TaskFlow — Team Task Manager",
  description: "Collaborative task management with AI assistant",
};

export default function RootLayout({ children }: { children: React.ReactNode }) {
  return (
    <html lang="en">
      <head>
        <link rel="preconnect" href="https://fonts.googleapis.com" />
        <link
          href="https://fonts.googleapis.com/css2?family=Syne:wght@400;600;700;800&family=DM+Sans:wght@300;400;500&display=swap"
          rel="stylesheet"
        />
      </head>
      <body>{children}</body>
    </html>
  );
}
EOF

echo "✓ app/layout.tsx"

# ── write remaining files via python ──────────────────────────────────────
python3 << 'PYEOF'
import base64, os

os.makedirs(os.path.dirname("app/globals.css") or ".", exist_ok=True)
open("app/globals.css", "w").write(base64.b64decode("").decode())
print("✓ app/globals.css")
os.makedirs(os.path.dirname("app/page.tsx") or ".", exist_ok=True)
open("app/page.tsx", "w").write(base64.b64decode("").decode())
print("✓ app/page.tsx")
os.makedirs(os.path.dirname("app/api/tasks/route.ts") or ".", exist_ok=True)
open("app/api/tasks/route.ts", "w").write(base64.b64decode("").decode())
print("✓ app/api/tasks/route.ts")
os.makedirs(os.path.dirname("app/api/tasks/[id]/route.ts") or ".", exist_ok=True)
open("app/api/tasks/[id]/route.ts", "w").write(base64.b64decode("").decode())
print("✓ app/api/tasks/[id]/route.ts")
os.makedirs(os.path.dirname("app/api/people/route.ts") or ".", exist_ok=True)
open("app/api/people/route.ts", "w").write(base64.b64decode("").decode())
print("✓ app/api/people/route.ts")
os.makedirs(os.path.dirname("app/api/ai-query/route.ts") or ".", exist_ok=True)
open("app/api/ai-query/route.ts", "w").write(base64.b64decode("").decode())
print("✓ app/api/ai-query/route.ts")
os.makedirs(os.path.dirname("lib/store.ts") or ".", exist_ok=True)
open("lib/store.ts", "w").write(base64.b64decode("").decode())
print("✓ lib/store.ts")
os.makedirs(os.path.dirname("lib/ai.ts") or ".", exist_ok=True)
open("lib/ai.ts", "w").write(base64.b64decode("").decode())
print("✓ lib/ai.ts")
PYEOF